import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient.js';

const Lancamento = () => {
  const [form, setForm] = useState({
    descricao: '', valor_total: '', loja: '', pedido: '', 
    nota_fiscal: '', parcelado: false, num_parcelas: 1, data_compra: ''
  });

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // Calcula o valor da parcela se for parcelado
    const valorParcela = form.parcelado ? (form.valor_total / form.num_parcelas) : form.valor_total;

    const { data, error } = await supabase
      .from('compras')
      .insert([{
        ...form,
        valor_total: parseFloat(form.valor_total),
        num_parcelas: parseInt(form.num_parcelas)
      }]);

    if (error) {
      alert("Erro ao salvar: " + error.message);
    } else {
      alert("Despesa lançada com sucesso!");
      // Limpa o formulário
    }
  };

// Trecho do retorno do componente Lancamento
return (
<div className="fade-in"> {/* <--- Adicionado aqui */}
  <div className="card"> {/* Envolvemos o formulário em um card branco */}
    <h2>Novo Lançamento</h2>
    <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
      <div className="input-group">
        <label>Data</label>
        <input type="date" className="form-control" required onChange={e => setForm({...form, data_compra: e.target.value})} />
      </div>
      
      <input placeholder="O que você comprou?" className="form-control" required onChange={e => setForm({...form, descricao: e.target.value})} />
      <input placeholder="Em qual loja?" className="form-control" onChange={e => setForm({...form, loja: e.target.value})} />
      
      <div className="input-row" style={{ display: 'flex', gap: '10px' }}>
        <input placeholder="Valor R$" type="number" step="0.01" className="form-control" required onChange={e => setForm({...form, valor_total: e.target.value})} />
        
        {form.parcelado && (
          <input type="number" placeholder="Parcelas" className="form-control" style={{ width: '100px' }} onChange={e => setForm({...form, num_parcelas: e.target.value})} />
        )}
      </div>

      <label className="checkbox-container">
        <input type="checkbox" checked={form.parcelado} onChange={e => setForm({...form, parcelado: e.target.checked})} />
        <span>Compra Parcelada?</span>
      </label>
      
      <button type="submit" className="btn-primary">
        Salvar Lançamento
      </button>
    </form>
  </div>
</div>
);
};

export default Lancamento;
